input.content:
// BAZ Refocus — single source of truth for the relaunch.
// One audience. One offer. One channel. (See docs/INTENSITY_PRINCIPLE.md)
//
// This file IS the strategy. Every page below imports it. Change the business
// here, not in the markup.

export const positioning = {
  // PART 1 — The smallest viable audience.
  // Not "ambitious businesses". A census is not a customer.
  audience: {
    name: "Technical founders & solo operators",
    who: "AI-native / software founders doing $20k–$250k/mo who build the product themselves",
    pains: [
      "Hate slow, junior-staffed agencies that send decks instead of results",
      "Don't have time to become a marketer and don't trust generalists",
      "Tried 5 channels at once, got noise, not signal",
    ],
    want: "One senior team that ships their entire marketing system and gets out of the way",
    antiAudience: "Enterprise procurement, brand-only plays, anyone who needs 3 quotes and a committee",
  },

  // PART 2 — Kill 80% of the menu. One hero offer.
  // The other 13 services still exist; they are NOT on the homepage.
  heroOffer: {
    id: "system-in-45",
    name: "Your marketing system, built and running in 45 days",
    promise: "One senior team. One channel. One funnel. Live in 45 days — or you don't pay.",
    price: "Flat $9,500 + 10% of attributed lift, first 90 days",
    outcome: "A compounding owned channel (email/SEO) + one paid channel at statistical significance",
    // The 13 services we deliberately HIDE from the front door:
    hiddenServices: [
      "Brand architecture & identity system",
      "UI/UX & front-end development",
      "Market intelligence report",
      "Competitor vulnerability audit",
      "Behavioral / persona modeling",
      "Predictive analytics engines",
      "CRM integration & migration",
      "Marketing automation & triggers",
      "Conversion funnel architecture",
      "Multi-channel campaign deployment",
      "Paid media & ad operations",
      "Content & creative production",
      "A/B testing & optimization",
      "Strategic positioning & roadmap",
    ],
  },

  // PART 3 — Agency or product? This quarter, the agency leads; the Hub is the tool.
  decision: {
    lead: "agency",
    note: "Marketing Hub is the weapon BAZ uses to deliver. It is NOT the product we sell this quarter. Selling both at once is extensity.",
    productStatus: "internal tool — used on every client, not marketed",
  },

  // PART 5 — The brand, rebuilt around our one remarkable idea.
  brand: {
    name: "BAZ",
    oldTagline: "The growth partner for ambitious businesses.",
    tagline: "Intensity beats extensity. We market like it.",
    manifesto: "One audience. One channel. One offer. Go deep, not wide.",
    principle: "Intensity beats extensity — every time.",
  },

  // PART 8 — Prove it on ONE channel first.
  channel: {
    primary: "Founder-led email + LinkedIn (owned + earned)",
    kpi: "Replies & calls booked from the list — not impressions",
    expandOnlyAfter: "Primary channel compounds for 90 days",
  },
};

export type Positioning = typeof positioning;

:root {
  --navy: #0b1f3a;
  --navy-2: #11294d;
  --ink: #0a0f1a;
  --paper: #f6f4ef;
  --gold: #c9a24b;
  --gold-2: #e3c172;
  --muted: #8a93a6;
  --line: #e2ddd2;
  --radius: 14px;
  --maxw: 760px;
}

* { box-sizing: border-box; }
html { scroll-behavior: smooth; }
body {
  margin: 0;
  font-family: ui-sans-serif, system-ui, -apple-system, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
  background: var(--paper);
  color: var(--ink);
  line-height: 1.6;
  -webkit-font-smoothing: antialiased;
}
a { color: inherit; }

.wrap { max-width: var(--maxw); margin: 0 auto; padding: 0 20px; }

/* Top nav */
nav {
  position: sticky; top: 0; z-index: 20;
  background: rgba(11,31,58,0.96);
  color: #fff; border-bottom: 1px solid rgba(255,255,255,0.08);
}
nav .wrap { display: flex; align-items: center; gap: 18px; height: 56px; }
nav .brand { font-weight: 800; letter-spacing: 2px; color: var(--gold-2); }
nav a { color: #cdd6e6; text-decoration: none; font-size: 14px; }
nav a:hover { color: #fff; }
nav .spacer { flex: 1; }

/* Hero */
.hero { background: var(--navy); color: #fff; padding: 84px 0 72px; }
.hero .kicker { color: var(--gold-2); text-transform: uppercase; letter-spacing: 3px; font-size: 12px; font-weight: 700; }
.hero h1 { font-size: clamp(30px, 6vw, 52px); line-height: 1.08; margin: 14px 0 18px; letter-spacing: -0.5px; }
.hero p { color: #c6d0e2; font-size: 18px; max-width: 600px; }
.hero .accent { color: var(--gold-2); }

/* Buttons */
.btn {
  display: inline-block; text-decoration: none; font-weight: 700;
  padding: 14px 22px; border-radius: 10px; font-size: 15px;
  background: var(--gold); color: var(--ink); border: 1px solid var(--gold);
  transition: transform .08s ease, background .15s ease;
}
.btn:hover { background: var(--gold-2); transform: translateY(-1px); }
.btn.ghost { background: transparent; color: #fff; border-color: rgba(255,255,255,0.3); }
.btn.ghost:hover { border-color: #fff; background: rgba(255,255,255,0.06); }

/* Sections */
section { padding: 56px 0; }
section.alt { background: #fff; border-top: 1px solid var(--line); border-bottom: 1px solid var(--line); }
h2 { font-size: clamp(24px, 4vw, 34px); letter-spacing: -0.4px; margin: 0 0 14px; }
h3 { font-size: 19px; margin: 26px 0 8px; }
.lead { font-size: 18px; color: #3a4252; }
.muted { color: var(--muted); }

/* Manifesto big type */
.manifesto { background: var(--ink); color: #fff; padding: 96px 0; text-align: center; }
.manifesto .big { font-size: clamp(34px, 8vw, 72px); font-weight: 800; line-height: 1.02; letter-spacing: -1px; }
.manifesto .big .g { color: var(--gold-2); }
.manifesto p { color: #aeb8cc; max-width: 560px; margin: 22px auto 0; }

/* Cards */
.card { background: #fff; border: 1px solid var(--line); border-radius: var(--radius); padding: 22px; }
.grid { display: grid; gap: 16px; }
.grid.cols-3 { grid-template-columns: repeat(3, 1fr); }
.grid.cols-2 { grid-template-columns: repeat(2, 1fr); }
@media (max-width: 680px) { .grid.cols-3, .grid.cols-2 { grid-template-columns: 1fr; } }
.card h4 { margin: 0 0 6px; font-size: 16px; }
.card .x { color: var(--muted); font-size: 14px; }

/* Offer block */
.offer { background: var(--navy-2); color: #fff; border-radius: var(--radius); padding: 28px; margin-top: 8px; }
.offer .price { color: var(--gold-2); font-weight: 800; font-size: 22px; }
.offer ul { margin: 12px 0 0; padding-left: 18px; color: #cdd6e6; }
.offer li { margin: 6px 0; }

/* Signup form */
.signup { background: #fff; border: 1px solid var(--line); border-radius: var(--radius); padding: 24px; }
.signup label { display: block; font-size: 13px; font-weight: 700; margin-bottom: 6px; color: #3a4252; }
.signup input {
  width: 100%; padding: 12px 14px; border: 1px solid var(--line); border-radius: 10px;
  font-size: 15px; margin-bottom: 12px;
}
.signup input:focus { outline: 2px solid var(--gold); border-color: var(--gold); }
.note { font-size: 13px; color: var(--muted); margin-top: 10px; }
.ok { color: #1c7a4a; font-weight: 700; }
.err { color: #b3261e; font-weight: 700; }

/* Parked list */
table { width: 100%; border-collapse: collapse; font-size: 14px; }
th, td { text-align: left; padding: 10px 12px; border-bottom: 1px solid var(--line); }
th { color: var(--muted); font-weight: 700; text-transform: uppercase; letter-spacing: 1px; font-size: 11px; }
.tag { display: inline-block; font-size: 11px; font-weight: 800; padding: 3px 8px; border-radius: 999px; letter-spacing: 1px; }
.tag.active { background: #e4f6ec; color: #1c7a4a; }
.tag.parked { background: #f0ece2; color: #8a6d2f; }

footer { background: var(--ink); color: #9aa6bd; padding: 36px 0; font-size: 13px; }
footer a { color: var(--gold-2); text-decoration: none; }

