import { Suspense } from "react";
import {
  Hero,
  PillarGrid,
  PerformanceFeature,
  ServicesOverview,
  HowWeWork,
  KpiBand,
  Framework,
  CaseStudies,
  LogoMarquee,
  Testimonials,
