import { NextRequest } from "next/server";
import { json, readJson } from "@/lib/api-helpers";
import { db, now, uid } from "@/lib/db";

export const dynamic = "force-dynamic";

export async function POST(req: NextRequest) {
  try {
    const body = await readJson<{ workspaceId?: string; userId?: string; x?: number; y?: number; page?: string }>(req);
    if (!body?.workspaceId || !body?.userId) {
      return json({ error: "workspaceId and userId required" }, 400);
    }
    const t = now();
    db.prepare(
      `INSERT OR REPLACE INTO presence (id, user_id, page, x, y, last_ping) VALUES (?, ?, ?, ?, ?, ?)`,
    ).run(uid("pres_"), body.userId, body.page || "/", body.x ?? 0, body.y ?? 0, t);
    return json({ ok: true });
  } catch (e) {
    return json({ error: e instanceof Error ? e.message : "Failed" }, 500);
  }
}

export async function GET(req: NextRequest) {
  try {
    const workspaceId = req.nextUrl.searchParams.get("workspaceId") || "default";
    const rows = db
      .prepare(
        `SELECT p.*, u.name, u.email FROM presence p LEFT JOIN users u ON u.id = p.user_id WHERE p.last_ping > ?`,
      )
      .all(now() - 5 * 60 * 1000) as Record<string, unknown>[];
    return json(rows);
  } catch (e) {
    return json({ error: e instanceof Error ? e.message : "Failed" }, 500);
  }
}

